section.code:
{
  "__faion_header__": {
    "methodology": "vui-conversation-design",
    "version": "1.1.0",
    "produces": "spec"
  },
  "states": [
    {
      "id": "ask-date",
      "allowed_intents": [
        "provide-date"
      ],
      "voice_script": "Which date works for you?",
      "screen_prompt": "Select a date below or say one out loud.",
      "no_match_handler": "reprompt: 'I didn't catch the date.'",
      "ambiguous_handler": "ask user to disambiguate"
    },
    {
      "id": "confirm",
      "allowed_intents": [
        "confirm",
        "deny"
      ],
      "voice_script": "Book Tuesday at 3 PM. Confirm?",
      "screen_prompt": "Confirm booking for Tuesday at 3 PM (Yes / No)",
      "no_match_handler": "reprompt: 'Say yes or cancel.'",
      "ambiguous_handler": "reprompt: 'Sorry, yes or cancel?'"
    }
  ],
  "reprompt_cap": 3,
  "noise_test_conditions": [
    "quiet",
    "ambient",
    "kitchen"
  ]
}
